Consider the following C program:

#include <stdio.h>
int r() {
    static int num = 7;
    return num--;
}
int main() {
    for (r(); r(); r())
        printf("%d", r());
    return 0;
}

Which one of the following is displayed on execution of the program?
A. 41
B. 52
C. 63
D. 630

Consider the following C program:

#include <stdio.h>
int main() {
    float sum = 0.0, j = 1.0, i = 2.0;
    while (i/j > 0.0625) {
        j = j + j;
        sum = sum + i/j;
        printf("%f\n", sum);
    }
    return 0;
}

The number of times the variable sum will be printed, when the above program is executed, is ________
A. 4
B. 5
C. 6
D. 7

